import ModuleBase from "../module/ModuleBase";
export default class StorageModule extends ModuleBase {

    constructor() {
        super();
        this.moduleName = "storage";
    }

    setObject(k, v) {
        if (v) {
            var v = JSON.stringify(v);
        }
        localStorage.setItem(k,v);
    }

    getValue(key, _def) {
        let v = localStorage.getItem(key);
        if (v) return v;
        if (_def) return _def;
        return null;
    }

    getObject(key, _def) {
        let v = this.getValue(key, _def);
        if (!v) return _def;
        return JSON.parse(v);
    }
}