import RandomUtil from "../../../mlframework/util/RandomUtil";

export default class FlyParticleEntity extends Laya.Script {

    constructor() {
        super();
    }

    onEnable() {
    }

    onDisable() {
    }

    setData(data) {
        this.data = data;
        this.owner.pos(data.x, data.y);
        this.loopTime = 0;
        Laya.Tween.to(this.owner,{x:data.endx,y:data.endy},800,Laya.Ease.sineOut,Laya.Handler.create(this,()=>{
            for (let i = 0; i < 10; i++) {
                this.showParticle(40,40);
            }
            data.complete && data.complete();
            this.owner.destroy();
        }));
    }

    onUpdate() {
        this.loopTime += Laya.timer.delta;
        if (this.loopTime >= 20) {
            this.showParticle();
            // this.showParticle();
            this.loopTime = 0;
        }
    }

    showParticle(xf = 5,yf=5) {
        let x = this.owner.x + RandomUtil.randomIntegerN2M(-xf, xf);
        let y = this.owner.y + RandomUtil.randomIntegerN2M(-xf, xf);
        let radiu = RandomUtil.randomIntegerN2M(5, 20);
        let color = this.data.particleColor;
        ml.particle.addCircleCmd(x, y, radiu, color);
    }
}