        // if(this.startDelay){
        // this.currentDelay-=Laya.timer.delta;
        // if(this.currentDelay<=0){
        //     this.reload();
        //     this.currentDelay = this.slideDelay;
        // }
        //     return;
        // }

        // if (this.left) {
        //     this.list.scrollBar.value -= 1;
        //     if (this.list.scrollBar.value <= 0) {
        //         this.left = false;
        //         this.startDelay = true;
