export default class WXInterstitial {

    constructor() {
        this.ad = null;
        this.loaded = false;
    }

    show(onShow, onclose) {
        this.onClose = onclose;
        this.ad && this.ad.show().then((res) => {
            onShow && onShow();
        });
    }

    load(id) {
        if(!id) return;
        this.id = id;
        this.ad = this._$createAd(id);
    }

    _$createAd(id) {
        if (!ML.mini.createInterstitialAd) {
            return null;
        }
        let ad = ML.mini.createInterstitialAd({
            adUnitId: id,
        });
        ad.onLoad(this._$onload.bind(this));
        ad.onClose(this._$onclose.bind(this));
        return ad;
    }

    _$onload() {
    }

    _$onclose() {
        this.onClose && this.onClose();
    }
}