import JQuery from "./JQuery";

export default class RandomUtil { };

RandomUtil.randomIntegerN2M = function (n, m) {
    var random = Math.floor(Math.random() * (m - n + 1) + n);
    return random;
};

RandomUtil.randomFloat = function (min, max) {
    var range = max - min;
    var rand = Math.random();
    var num = min + (rand * range);
    return num;
}

RandomUtil.probabilityCanHappen = function (num) {
    let random = RandomUtil.randomIntegerN2M(0, 100);
    return random <= num;
};
//传入概率值数组，返回中标的概率下标
RandomUtil.probabilitys = function (parr) {
    var arr = 0;
    var pres = JQuery.clone(parr);
    var probabilityCount = 0;
    for (let i = 0; i < pres.length; i++) {
        probabilityCount += pres[i];
    }
    if (probabilityCount != 100) {
        console.error('所有概率值总和不等于100%');
    }
    var nums = new Array();
    for (let i = 0; i < pres.length; i++) {
        const element = pres[i];
        for (let index = 0; index < element; index++) {
            nums.push(arr);
        }
        arr++;
    }
    var random = RandomUtil.randomIntegerN2M(0, 99);
    var targetIndex = nums[random];
    return targetIndex;
};

RandomUtil.weight = function (weigths) {
    let flag = 0;
    let total = 0;
    let tempWeigths = JQuery.clone(weigths);
    for (let i = 0; i < tempWeigths.length; i++) {
        let weight = tempWeigths[i];
        total += weight;
    }
    let nums = [];
    for (let i = 0; i < tempWeigths.length; i++) {
        let weigth = tempWeigths[i];
        for (let j = 0; j < weigth; j++) {
            nums.push(flag);
        }
        flag++;
    }
    let random = RandomUtil.randomIntegerN2M(0, total - 1);
    let targetIndex = nums[random];
    return targetIndex;
}