import ModuleBase from "../../../mlframework/module/ModuleBase";
import JQuery from "../../../mlframework/util/JQuery";
import Tools from "../../../mlframework/util/Tools";
import ChestModuleConfig from "./ChestModuleConfig";
import RandomUtil from "../../../mlframework/util/RandomUtil";
export default class ChestModule extends ModuleBase {

    constructor() {
        super();
        this.moduleName = "chest";
        this._data = null;
    }

    onAwake() {
        this._data = JQuery.clone(ChestModuleConfig.data);
    }

    onEnable() {
    }

    onDisable() {
    }
    /**
     * 获取宝箱数据
     */
    getChestList() {
        //过滤已经解锁的皮肤
        this._$filterUnlocked();
        //随机最佳奖励类型
        let bestType = RandomUtil.probabilitys([50, 50]);  //金币、皮肤
        if (this._data.bestskin.length == 0) {
            bestType = 1;  //金币
        }
        let chestObj = {};
        chestObj.bestType = bestType;
        chestObj.list = [];
        //没有皮肤了，设置最佳奖励为金币
        if (bestType == 1) {
            //金币
            chestObj.bestValue = this._data.bestGold;
            chestObj.list.push({
                type:1,
                best:true,
                value:this._data.bestGold,
            });
        } else {
            //皮肤
            let bestOneId = Tools.RandomOne(this._data.bestskin);
            let skinData = ml.skin.getDataById(parseInt(bestOneId));
            chestObj.bestValue = skinData;
            chestObj.list.push({
                type:0,
                best:true,
                value:skinData,
            });
        }
        this._data.normal.forEach(item => {
            let cell = {
                type: 1,
                best:false,
                value: item,
            }
            chestObj.list.push(cell);
        });

        //打乱顺序
        Tools.RandomSort(chestObj.list);
        return chestObj;
    }

    /**
     *  去重
     */
    _$filterUnlocked() {

        let tmp = [];
        this._data.bestskin.forEach(id => {
            let exist = ml.skin.checkUnlockedById(id);
            if (!exist) {
                tmp.push(id);
            }
        });
        this._data.bestskin = tmp;
    }


}