import RandomUtil from "../../../mlframework/util/RandomUtil";

export default class UIParticleSpriteEntity extends Laya.Script {

    constructor() {
        super();
    }

    onEnable() {
    }

    onDisable() {
    }

    setData(skin, start, end, complete) {
        this.owner.pos(start.x, start.y);
        this.endPos = end;
        this.loopTime = 0;
        Laya.Tween.to(this.owner,{x:end.x,y:end.y},800,Laya.Ease.sineOut,Laya.Handler.create(this,()=>{
            this.owner.destroy();
        }));
    }

    onUpdate() {
        this.loopTime += Laya.timer.delta;
        if (this.loopTime >= 20) {
            this.showParticle();
            this.showParticle();
            this.loopTime = 0;
        }
        // let t = 0.05;
        // this.owner.x = this.owner.x + t * (this.endPos.x - this.owner.x);
        // this.owner.y = this.owner.y + t * (this.endPos.y - this.owner.y);
        // this.owner.x = this.loopTime*Math.pow(100,);
        // this.owner.x = this.loopTime*100;
    }

    showParticle() {
        let x = this.owner.x + RandomUtil.randomIntegerN2M(-5, 5);
        let y = this.owner.y + RandomUtil.randomIntegerN2M(-5, 5);
        let radiu = RandomUtil.randomIntegerN2M(5, 20);
        let color = "#F8CE65";
        ml.particle.addCircleCmd(x, y, radiu, color);
    }
}