import ModuleBase from "../../../mlframework/module/ModuleBase";
import UserDataModuleConfig from "./UserDataModuleConfig";
import JQuery from "../../../mlframework/util/JQuery";
import Tools from "../../../mlframework/util/Tools";
import RandomUtil from "../../../mlframework/util/RandomUtil";

export default class UserDataModule extends ModuleBase {

    constructor() {
        super();
        this.moduleName = 'user';
        this._userData = null;
        this._dataTemplate = UserDataModuleConfig.data;
    }
    onAwake() {
        this.initUserData();
    }

    onEnable() {
    }

    onDisable() {
    }

    get UserData() {
        if (this._userData != null) {
            return this._userData;
        }
        this.initUserData();
    }

    initUserData() {
        this._userData = this._getDataFromLocalStorage();
        if (this._userData != null) {
            return this._userData;
        }
        this._userData = this._dataTemplate;
    }

    _getDataFromLocalStorage() {
        let localData = ML.storage.getObject("User_data", null);
        if (localData) {
            return JQuery.extend(true, this._dataTemplate, localData);
        }
        return this._dataTemplate;
    }

    saveUser() {
        ML.storage.setObject("User_data", this._userData);
    }

    //---------------------------------------

    addGold(v) {
        if (!Tools.IsNumber(v)) {
            console.error('user 金币数不为数字');
            return;
        }
        let afterAdd = this.UserData.gold + v;
        if (afterAdd < 0) {
            afterAdd = 0;
            console.warn('user 消耗的金币数大于金币余额，请检查是否有逻辑错误');
        }
        this.UserData.gold = afterAdd;
        ML.event.emit("User_dataChanged");
        this.saveUser();
    }

    // 加宝箱钥匙，最多3把
    addKey(v) {
        if (!Tools.IsNumber(v)) {
            console.error('user 钥匙数不为数字');
            return;
        }
        let afterAdd = this.UserData.key + v;
        if (afterAdd < 0) {
            afterAdd = 0;
        }
        //最多3把钥匙
        if (afterAdd > 3) {
            afterAdd = 3;
        }
        this.UserData.key = afterAdd;
        ML.event.emit("User_dataChanged");
        this.saveUser();
    }


    //清空宝箱钥匙
    clearKey() {
        this.UserData.key = 0;
        ML.event.emit("User_dataChanged");
        this.saveUser();
    }

    // 加关卡数
    addLevel(v = 1) {
        if (!Tools.IsNumber(v)) {
            return;
        }
        this.UserData.level += v;
        this.addRealLevel(v);
        ML.event.emit("User_dataChanged");
        this.saveUser();
    }
    
    addRealLevel(v = 1) {
        if (!Tools.IsNumber(v)) {
            return;
        }
        //现有40关
        if (this.UserData.realLevel > UserDataModuleConfig.LevelCountNow) {
            return;
        }
        this.UserData.realLevel += v;
    }

    getRealLevel() {
        let levelOfShow = this.UserData.level;
        let l = this.UserData.realLevel;
        if (l > UserDataModuleConfig.LevelCountNow) {//大于配置关卡
            //随机一个关卡给玩家，显示关卡数不变，真实关卡重复
            l = RandomUtil.randomIntegerN2M(1, UserDataModuleConfig.LevelCountNow);
        }
        return l;
    }
}