export default class SingleAdButton extends Laya.Script{
    constructor() {
        super();
        
    }

    onEnable() {
        
    }

    onDisable() {
    }

    init(){
        this.btn = new Laya.Image('ui/exit_btn.png');
        this.btn.size(168,64);
        this.btn.centerX = 0;
        this.btn.centerY = 0;
        this.btn.on("click", this, this._onBtnClick);
        this.owner.addChild(this.btn);
    }

    _onBtnClick(){
        ml.qy.showAdExit();
    }
}