export default class MLDictionary {
    constructor() {
        this._size = 0;
        this.data = {};
    }

    size() {
        return this._size;
    }

    clear() {
        this.data = {};
        this._size = 0;
    }

    add(k, v) {
        if (!this.containKey(k)) {
            this._size++;
        }
        this.data[k] = v;
    }

    remove(k) {
        if (this.containKey(k) && (delete this.data[k])) {
            this._size--;
        }
    }

    valueForKey(k) {
        return this.containKey(k) ? this.data[k] : null;
    }

    keyForValue(v) {
        for (var prop in this.data) {
            if (this.data[prop] === v) {
                return prop;
            }
        }
        return null;
    }

    getAllKeys() {
        var keys = [];
        for (var prop in this.data) {
            keys.push(prop);
        }
        return keys;
    }

    getAllValues() {
        var values = [];
        for (var prop in this.data) {
            values.push(this.data[prop]);
        }
        return values;
    }

    containKey(k) {
        return (k in this.data);
    }
}