import WebPlatformConfig from "./platforms/WebPlatformConfig";
import WebResourceModuleHelper from "../resource/WebResourceModuleHelper";
import WXResourceModuleHelper from "../resource/WXResourceModuleHelper";
import WXPlatformConfig from "./platforms/WXPlatformConfig";
import WebPlatformHelper from "../platform/WebPlatformHelper";
import MiniPlatformHelper from "../platform/MiniPlatformHelper";
import OVPlatformHelper from "../platform/OVPlatformHelper";
import WebAdHelper from "../ad/web/WebAdHelper";
import WXAdHelper from "../ad/wx/WXAdHelper";
import QQPlatformConfig from "./platforms/QQPlatformConfig";
import OPPOPlatformConfig from "./platforms/OPPOPlatformConfig";
import VIVOPlatformConfig from "./platforms/VIVOPlatformConfig";
import TTPlatformConfig from "./platforms/TTPlatformConfig";
import WebPlatformAudioHelper from "../audio/WebPlatformAudioHelper";
import MiniPlatformAudioHelper from "../audio/MiniPlatformAudioHelper";
import OPPOAdHelper from "../ad/oppo/OPPOAdHelper";

export default class Platform {
}
/**
 *Platform定义了各个平台的平台名和平台api调用前最 
 */

//平台名
Platform.WEB = "WEB";
Platform.WX = "WX";
Platform.QQ = "QQ";
Platform.OPPO = "OPPO";
Platform.VIVO = "VIVO";
Platform.TT = "TT";

//平台api调用命名空间
Platform.NameSpace = {
    WEB: "",
    WX: "wx",
    QQ: "qq",
    OPPO: "qg",
    VIVO: "qg",
    TT: "tt"
};
//平台配置类
Platform.Config = {
    WEB: WebPlatformConfig,
    WX: WXPlatformConfig,
    QQ: QQPlatformConfig,
    OPPO: OPPOPlatformConfig,
    VIVO: VIVOPlatformConfig,
    TT: TTPlatformConfig,
};

Platform.ResourceLoader = {
    WEB: WebResourceModuleHelper,
    WX: WXResourceModuleHelper,
    QQ: WXResourceModuleHelper,
    OPPO: WebResourceModuleHelper,
    VIVO: WXResourceModuleHelper,
    TT: WebResourceModuleHelper,
};

Platform.Helper = {
    WEB: WebPlatformHelper,
    WX: MiniPlatformHelper,
    QQ: MiniPlatformHelper,
    OPPO: OVPlatformHelper,
    VIVO: OVPlatformHelper,
    TT: MiniPlatformHelper,
};

Platform.Ad = {
    WEB: WebAdHelper,
    WX: WXAdHelper,
    QQ: WXAdHelper,
    OPPO: OPPOAdHelper,
    VIVO: WXAdHelper,
    TT: WXAdHelper,
};

Platform.Audio = {
    WEB: WebPlatformAudioHelper,
    WX: MiniPlatformAudioHelper,
    QQ: MiniPlatformAudioHelper,
    OPPO: MiniPlatformAudioHelper,
    VIVO: MiniPlatformAudioHelper,
    TT: MiniPlatformAudioHelper,
};